package lru

// node is an element in the intrusive doubly linked list.
type node struct {
	key, value int64
	prev, next *node
}

// LRUCache is a fixed-capacity least-recently-used cache with int64 keys/values.
// All operations are O(1) average using a hashmap + doubly linked list.
type LRUCache struct {
	capacity int
	items    map[int64]*node
	// head is the sentinel; head.next is the most-recently-used,
	// head.prev is the least-recently-used.
	head *node
}

// NewLRUCache creates a cache with the given positive capacity.
func NewLRUCache(capacity int) *LRUCache {
	if capacity <= 0 {
		panic("lru: capacity must be > 0")
	}
	h := &node{}
	h.prev = h
	h.next = h
	return &LRUCache{
		capacity: capacity,
		items:    make(map[int64]*node, capacity),
		head:     h,
	}
}

// unlink removes n from the linked list.
func (c *LRUCache) unlink(n *node) {
	n.prev.next = n.next
	n.next.prev = n.prev
}

// pushFront inserts n right after the sentinel head (most-recently-used).
func (c *LRUCache) pushFront(n *node) {
	n.prev = c.head
	n.next = c.head.next
	c.head.next.prev = n
	c.head.next = n
}

// moveToFront marks n as most-recently-used.
func (c *LRUCache) moveToFront(n *node) {
	c.unlink(n)
	c.pushFront(n)
}

// Get returns the value for key and marks it most-recently-used.
// The second return value reports whether the key was present.
func (c *LRUCache) Get(key int64) (int64, bool) {
	n, ok := c.items[key]
	if !ok {
		return 0, false
	}
	c.moveToFront(n)
	return n.value, true
}

// Put inserts or updates key with value, marking it most-recently-used.
// Inserting a new key when at capacity evicts the least-recently-used key first.
func (c *LRUCache) Put(key, value int64) {
	if n, ok := c.items[key]; ok {
		n.value = value
		c.moveToFront(n)
		return
	}
	if len(c.items) >= c.capacity {
		// Evict least-recently-used (head.prev).
		lru := c.head.prev
		c.unlink(lru)
		delete(c.items, lru.key)
	}
	n := &node{key: key, value: value}
	c.pushFront(n)
	c.items[key] = n
}

// Len returns the number of items currently stored.
func (c *LRUCache) Len() int {
	return len(c.items)
}

package lru

import "testing"

// 1. put/get basic hit.
func TestPutGetBasicHit(t *testing.T) {
	c := NewLRUCache(2)
	c.Put(1, 100)
	v, ok := c.Get(1)
	if !ok || v != 100 {
		t.Fatalf("expected (100,true), got (%d,%v)", v, ok)
	}
}

// 2. get on missing key returns not-found.
func TestGetMissing(t *testing.T) {
	c := NewLRUCache(2)
	v, ok := c.Get(42)
	if ok || v != 0 {
		t.Fatalf("expected (0,false), got (%d,%v)", v, ok)
	}
}

// 3. Update existing key changes value, no eviction.
func TestUpdateNoEviction(t *testing.T) {
	c := NewLRUCache(2)
	c.Put(1, 10)
	c.Put(2, 20)
	c.Put(1, 11) // update existing, must not evict
	if c.Len() != 2 {
		t.Fatalf("expected size 2, got %d", c.Len())
	}
	if v, ok := c.Get(1); !ok || v != 11 {
		t.Fatalf("expected (11,true), got (%d,%v)", v, ok)
	}
	if v, ok := c.Get(2); !ok || v != 20 {
		t.Fatalf("expected (20,true), got (%d,%v)", v, ok)
	}
}

// 4. Exceeding capacity evicts the LRU key.
func TestExceedCapacityEvictsLRU(t *testing.T) {
	c := NewLRUCache(2)
	c.Put(1, 10)
	c.Put(2, 20)
	c.Put(3, 30) // evicts key 1 (LRU)
	if _, ok := c.Get(1); ok {
		t.Fatalf("expected key 1 to be evicted")
	}
	if v, ok := c.Get(2); !ok || v != 20 {
		t.Fatalf("expected (20,true) for key 2, got (%d,%v)", v, ok)
	}
	if v, ok := c.Get(3); !ok || v != 30 {
		t.Fatalf("expected (30,true) for key 3, got (%d,%v)", v, ok)
	}
}

// 5. get() refreshes recency (the got key survives a subsequent eviction).
func TestGetRefreshesRecency(t *testing.T) {
	c := NewLRUCache(2)
	c.Put(1, 10)
	c.Put(2, 20)
	if _, ok := c.Get(1); !ok { // refresh key 1
		t.Fatalf("expected key 1 present")
	}
	c.Put(3, 30) // now key 2 is LRU and should be evicted
	if _, ok := c.Get(2); ok {
		t.Fatalf("expected key 2 to be evicted")
	}
	if v, ok := c.Get(1); !ok || v != 10 {
		t.Fatalf("expected key 1 to survive: got (%d,%v)", v, ok)
	}
}

// 6. Capacity 1 edge case.
func TestCapacityOne(t *testing.T) {
	c := NewLRUCache(1)
	c.Put(1, 10)
	if v, ok := c.Get(1); !ok || v != 10 {
		t.Fatalf("expected (10,true), got (%d,%v)", v, ok)
	}
	c.Put(2, 20) // evicts key 1
	if _, ok := c.Get(1); ok {
		t.Fatalf("expected key 1 evicted at capacity 1")
	}
	if v, ok := c.Get(2); !ok || v != 20 {
		t.Fatalf("expected (20,true), got (%d,%v)", v, ok)
	}
	if c.Len() != 1 {
		t.Fatalf("expected size 1, got %d", c.Len())
	}
}

// 7. Overwrite refreshes recency.
func TestOverwriteRefreshesRecency(t *testing.T) {
	c := NewLRUCache(2)
	c.Put(1, 10)
	c.Put(2, 20)
	c.Put(1, 11) // overwrite key 1 -> becomes MRU
	c.Put(3, 30) // key 2 is LRU -> evicted
	if _, ok := c.Get(2); ok {
		t.Fatalf("expected key 2 to be evicted")
	}
	if v, ok := c.Get(1); !ok || v != 11 {
		t.Fatalf("expected key 1 to survive with 11: got (%d,%v)", v, ok)
	}
	if v, ok := c.Get(3); !ok || v != 30 {
		t.Fatalf("expected (30,true) for key 3, got (%d,%v)", v, ok)
	}
}

package main

import (
	"fmt"
	"time"

	"lru"
)

const (
	capacity   = 10_000
	totalOps   = 1_000_000
	keyspace   = 20_000
	lcgMul     = 6364136223846793005
	lcgInc     = 1442695040888963407
	initialSt  = 42
)

// runPass executes one full pass of the deterministic workload against c,
// starting from the given LCG state. It returns the final LCG state and the
// wrapping-u64 checksum of all successful-get values.
func runPass(c *lru.LRUCache, state uint64) (uint64, uint64) {
	var checksum uint64
	for i := 0; i < totalOps; i++ {
		state = lcgMul*state + lcgInc // wrapping uint64 arithmetic
		key := int64((state >> 33) % keyspace)
		if state&1 == 0 {
			if v, ok := c.Get(key); ok {
				checksum += uint64(v) // wrapping u64 sum
			}
		} else {
			c.Put(key, key)
		}
	}
	return state, checksum
}

func main() {
	// Warm-up pass (not timed). Fresh cache, LCG starts from seed.
	c := lru.NewLRUCache(capacity)
	state := uint64(initialSt)
	state, _ = runPass(c, state)

	// Timed pass: continue the LCG sequence from where warm-up ended,
	// reusing the warmed cache.
	start := time.Now()
	_, checksum := runPass(c, state)
	elapsed := time.Since(start).Seconds()

	opsPerSec := float64(totalOps) / elapsed

	fmt.Printf("total_ops:   %d\n", totalOps)
	fmt.Printf("elapsed_s:   %.6f\n", elapsed)
	fmt.Printf("ops_per_sec: %.0f\n", opsPerSec)
	fmt.Printf("final_size:  %d\n", c.Len())
	fmt.Printf("checksum:    %d\n", checksum)
}

